#include <stdio.h>
#include <stdlib.h>
int main()
{
   long long N,x=0;
   scanf("%lld",&N);
   while(x*(x+1)/2<N)
    x++;
   printf("%lld\n",N-x*(x-1)/2);
    return 0;
}

