fn main() {
    let mut text = String::new();
    std::io::stdin().read_line(&mut text).unwrap();
    let val: u64 = text.trim().parse().unwrap();
    let mut i = 1;
    let value = loop {
        if summation(i) >= val {
            break i;
        }
        i += 1;
    };
    println!("{}", val - summation(value - 1))
}
fn summation(i: u64) -> u64 {
    (i * (i + 1)) / 2
}
